export declare const CSS_NAMESPACE = "smx-nav";
export declare const styles = "\n.smx-nav {\n  --smx-bg: #ffffff;\n  --smx-fg: #1a1a2e;\n  --smx-fg-secondary: #64748b;\n  --smx-border: #e2e8f0;\n  --smx-active-bg: #f0f4ff;\n  --smx-active-fg: #3b5bdb;\n  --smx-active-border: #3b5bdb;\n  --smx-hover-bg: #f8fafc;\n  --smx-font: -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, \"Helvetica Neue\", Arial, sans-serif;\n  --smx-radius: 6px;\n  --smx-transition: 150ms ease;\n\n  box-sizing: border-box;\n  font-family: var(--smx-font);\n  background: var(--smx-bg);\n  border-bottom: 1px solid var(--smx-border);\n  display: flex;\n  align-items: center;\n  padding: 0 16px;\n  height: 48px;\n  gap: 4px;\n  user-select: none;\n  -webkit-font-smoothing: antialiased;\n  -moz-osx-font-smoothing: grayscale;\n}\n\n.smx-nav *,\n.smx-nav *::before,\n.smx-nav *::after {\n  box-sizing: border-box;\n}\n\n.smx-nav.smx-nav--dark {\n  --smx-bg: #0f1117;\n  --smx-fg: #e2e8f0;\n  --smx-fg-secondary: #94a3b8;\n  --smx-border: #1e293b;\n  --smx-active-bg: #1a2340;\n  --smx-active-fg: #7c9aff;\n  --smx-active-border: #7c9aff;\n  --smx-hover-bg: #1a1d2e;\n}\n\n.smx-nav__logo {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  margin-right: 12px;\n  text-decoration: none;\n  color: var(--smx-fg);\n  font-weight: 700;\n  font-size: 15px;\n  letter-spacing: -0.01em;\n  white-space: nowrap;\n  flex-shrink: 0;\n}\n\n.smx-nav__logo svg {\n  width: 22px;\n  height: 22px;\n  flex-shrink: 0;\n}\n\n.smx-nav__items {\n  display: flex;\n  align-items: center;\n  gap: 2px;\n  list-style: none;\n  margin: 0;\n  padding: 0;\n  height: 100%;\n  overflow-x: auto;\n  scrollbar-width: none;\n}\n\n.smx-nav__items::-webkit-scrollbar {\n  display: none;\n}\n\n.smx-nav__item {\n  margin: 0;\n  padding: 0;\n  height: 100%;\n  display: flex;\n  align-items: center;\n}\n\n.smx-nav__link {\n  display: flex;\n  align-items: center;\n  gap: 6px;\n  padding: 6px 12px;\n  border-radius: var(--smx-radius);\n  text-decoration: none;\n  color: var(--smx-fg-secondary);\n  font-size: 13px;\n  font-weight: 500;\n  white-space: nowrap;\n  transition: color var(--smx-transition), background-color var(--smx-transition);\n  position: relative;\n  line-height: 1;\n}\n\n.smx-nav__link:hover {\n  color: var(--smx-fg);\n  background: var(--smx-hover-bg);\n}\n\n.smx-nav__link--active {\n  color: var(--smx-active-fg);\n  background: var(--smx-active-bg);\n}\n\n.smx-nav__link--active:hover {\n  color: var(--smx-active-fg);\n  background: var(--smx-active-bg);\n}\n\n.smx-nav__link-icon {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  width: 16px;\n  height: 16px;\n  flex-shrink: 0;\n}\n\n.smx-nav__link-icon > svg {\n  width: 100%;\n  height: 100%;\n}\n\n/* Left/sidebar position variant */\n.smx-nav.smx-nav--left {\n  flex-direction: column;\n  align-items: stretch;\n  height: auto;\n  width: 220px;\n  border-bottom: none;\n  border-right: 1px solid var(--smx-border);\n  padding: 12px 8px;\n  gap: 2px;\n}\n\n.smx-nav.smx-nav--left .smx-nav__logo {\n  margin-right: 0;\n  margin-bottom: 12px;\n  padding: 4px 8px;\n}\n\n.smx-nav.smx-nav--left .smx-nav__items {\n  flex-direction: column;\n  height: auto;\n  gap: 2px;\n}\n\n.smx-nav.smx-nav--left .smx-nav__item {\n  height: auto;\n}\n\n.smx-nav.smx-nav--left .smx-nav__link {\n  padding: 8px 10px;\n  width: 100%;\n}\n\n@media (prefers-color-scheme: dark) {\n  .smx-nav.smx-nav--auto {\n    --smx-bg: #0f1117;\n    --smx-fg: #e2e8f0;\n    --smx-fg-secondary: #94a3b8;\n    --smx-border: #1e293b;\n    --smx-active-bg: #1a2340;\n    --smx-active-fg: #7c9aff;\n    --smx-active-border: #7c9aff;\n    --smx-hover-bg: #1a1d2e;\n  }\n}\n";
